import React, { useState, useEffect } from 'react';
import Sidebar from '../components/Sidebar';
import Navbar from '../components/Navbar';

const MyReturns = () => {
  const [returns, setReturns] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeStatus, setActiveStatus] = useState('all');
  const [dateFilter, setDateFilter] = useState('');
  const [searchFilter, setSearchFilter] = useState('');

  // Mock return data
  const mockReturns = [
    {
      id: 1,
      carName: 'Toyota Wigo',
      carImage: 'https://i.imgur.com/d8xwD0J.png',
      bookingId: 'BR1024',
      returnDate: '2024-04-24',
      returnLocation: 'Tacloban City, Leyte',
      status: 'paid',
      invoiced: 1500,
      totalAmount: 3000,
      rating: 5,
      completedTrips: 16
    },
    {
      id: 2,
      carName: 'Toyota Vios',
      carImage: 'https://i.imgur.com/Im0UTUI.png',
      bookingId: 'BR1186',
      returnDate: '2026-02-26',
      returnLocation: 'Tacloban City, Leyte',
      status: 'inspected',
      invoiced: 1800,
      totalAmount: 3600,
      rating: 5,
      completedTrips: 16
    },
    {
      id: 3,
      carName: 'Toyota Hilux',
      carImage: 'https://i.imgur.com/9Jkyyo6.png',
      bookingId: 'BR1201',
      returnDate: '2026-01-06',
      returnLocation: 'Tacloban City, Leyte',
      status: 'paid',
      invoiced: 2500,
      totalAmount: 5000,
      rating: 5,
      completedTrips: 16
    }
  ];

  useEffect(() => {
    // Simulate loading data
    setTimeout(() => {
      setReturns(mockReturns);
      setLoading(false);
    }, 500);
  }, []);

  const updateStatusButtons = (clickedBtn, status) => {
    setActiveStatus(status);
  };

  const filterReturns = () => {
    const dateVal = dateFilter;
    const searchVal = searchFilter.trim().toLowerCase();

    setReturns(prevReturns => {
      return prevReturns.map(card => {
        // Check by status
        const cardFilter = card.status.toLowerCase();
        let statusMatch = (activeStatus === 'all') || (cardFilter === activeStatus);

        // Check by date (date must be same or after filter date)
        let dateMatch = true;
        if (dateVal) {
          dateMatch = card.returnDate >= dateVal;
        }

        // Check by search on booking id, car model, location
        const bookingId = card.bookingId.toLowerCase();
        const car = card.carName.toLowerCase();
        const location = card.returnLocation.toLowerCase();
        let searchMatch = false;
        if (searchVal === '') {
          searchMatch = true;
        } else {
          searchMatch = (bookingId.includes(searchVal) || car.includes(searchVal) || location.includes(searchVal));
        }

        return { ...card, visible: statusMatch && dateMatch && searchMatch };
      });
    });
  };

  const handleStatusFilter = (status) => {
    updateStatusButtons(null, status);
    filterReturns();
  };

  const handleDateFilter = () => {
    filterReturns();
  };

  const handleSearchFilter = (e) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      filterReturns();
    }
  };

  const formatDate = (dateStr) => {
    const date = new Date(dateStr);
    const months = ['January', 'February', 'March', 'April', 'May', 'June', 
                    'July', 'August', 'September', 'October', 'November', 'December'];
    return `${months[date.getMonth()]} ${date.getDate()}, ${date.getFullYear()}`;
  };

  const formatShortDate = (dateStr) => {
    const date = new Date(dateStr);
    const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 
                    'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    return `${months[date.getMonth()]} ${date.getDate()}, ${date.getFullYear()}`;
  };

  const getStatusClass = (status) => {
    switch(status) {
      case 'paid':
        return 'paid';
      case 'inspected':
        return 'inspected';
      case 'invoiced':
        return 'invoiced';
      default:
        return 'pending';
    }
  };

  const renderStars = (rating) => {
    return Array(5).fill(0).map((_, i) => (
      <svg key={i} viewBox="0 0 24 24" fill={i < rating ? "currentColor" : "none"} stroke="currentColor" strokeWidth="2">
        <path d="M12 17.27L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2 9.19 8.63 2 9.24l5.46 4.73L5.82 21z"/>
      </svg>
    ));
  };

  return (
    <div style={styles.container}>
      <Navbar />
      <Sidebar />
      
      <div style={styles.dashboardContent}>
        <style>{cssStyles}</style>
        
        <h2>My Returns</h2>

        <div className="filter-bar" role="search" aria-label="Filter returns and search">
          <button 
            type="button" 
            className={`status-filter ${activeStatus === 'all' ? 'active' : 'inactive'}`} 
            aria-pressed={activeStatus === 'all'} 
            data-filter="all"
            onClick={() => handleStatusFilter('all')}
          >
            All
          </button>
          <button 
            type="button" 
            className={`status-filter ${activeStatus === 'inspected' ? 'active' : 'inactive'}`} 
            aria-pressed={activeStatus === 'inspected'} 
            data-filter="inspected"
            onClick={() => handleStatusFilter('inspected')}
          >
            Inspected
          </button>
          <button 
            type="button" 
            className={`status-filter ${activeStatus === 'invoiced' ? 'active' : 'inactive'}`} 
            aria-pressed={activeStatus === 'invoiced'} 
            data-filter="invoiced"
            onClick={() => handleStatusFilter('invoiced')}
          >
            Invoiced
          </button>
          <button 
            type="button" 
            className={`status-filter ${activeStatus === 'paid' ? 'active' : 'inactive'}`} 
            aria-pressed={activeStatus === 'paid'} 
            data-filter="paid"
            onClick={() => handleStatusFilter('paid')}
          >
            Paid
          </button>

          <input 
            type="date" 
            aria-label="Choose date" 
            id="dateFilter" 
            value={dateFilter}
            onChange={(e) => setDateFilter(e.target.value)}
            onBlur={handleDateFilter}
          />

          <input
            type="search"
            placeholder="Search..."
            aria-label="Search returns"
            spellCheck="false"
            id="searchFilter"
            value={searchFilter}
            onChange={(e) => setSearchFilter(e.target.value)}
            onKeyDown={handleSearchFilter}
          />

          <button type="button" className="filter-btn" aria-label="Apply filters" onClick={filterReturns}>
            Filter
          </button>
        </div>

        <section className="returns-container" id="returnsList" aria-live="polite" aria-atomic="true">
          {loading ? (
            <div style={styles.loading}>Loading returns...</div>
          ) : returns.length === 0 ? (
            <div style={styles.emptyState}>
              <p>No returns found</p>
            </div>
          ) : (
            returns.map((returnItem) => (
              <article 
                key={returnItem.id} 
                className="return-card" 
                data-filter={returnItem.status}
                data-status={returnItem.status}
                data-invoiced={returnItem.invoiced}
                data-car={returnItem.carName}
                data-bookingid={returnItem.bookingId}
                data-location={returnItem.returnLocation}
                data-date={returnItem.returnDate}
                data-price={returnItem.totalAmount}
                aria-label={`Return entry for ${returnItem.carName} booking ${returnItem.bookingId} with status ${returnItem.status}`}
                style={returnItem.visible === false ? { display: 'none' } : {}}
              >
                <img src={returnItem.carImage} alt={returnItem.carName} loading="lazy" />
                <div className="return-info">
                  <strong className="booking-id">{returnItem.bookingId}</strong>
                  <span className="car-model">{returnItem.carName}</span>

                  {returnItem.rating > 0 && (
                    <div className="stars" aria-label={`${returnItem.rating} star rating, ${returnItem.completedTrips} completed`}>
                      {renderStars(returnItem.rating)}
                      <small>{returnItem.completedTrips} Complete</small>
                    </div>
                  )}

                  <div className="return-dates-status">
                    <span className="status-label-small past" aria-label="Return status Past">Past</span>

                    <div className="date-icon" aria-label={`Returned on ${formatDate(returnItem.returnDate)}`}>
                      <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true" focusable="false">
                        <rect x="3" y="4" width="18" height="18" rx="2" ry="2" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round"/>
                        <line x1="16" y1="2" x2="16" y2="6" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round"/>
                        <line x1="8" y1="2" x2="8" y2="6" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round"/>
                        <line x1="3" y1="10" x2="21" y2="10" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round"/>
                      </svg>
                      {formatShortDate(returnItem.returnDate)}
                    </div>

                    <div className="location-icon" aria-label={`Return location ${returnItem.returnLocation}`}>
                      <svg fill="none" stroke="#444" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" viewBox="0 0 24 24" aria-hidden="true" focusable="false">
                        <path d="M12 21c-4.97 0-9-7-9-10a9 9 0 1 1 18 0c0 3-4.03 10-9 10z"/>
                        <circle cx="12" cy="11" r="2"/>
                      </svg>
                      {returnItem.returnLocation}
                    </div>

                    <span className="status-label-small invoiced" aria-label={`Invoiced amount ${returnItem.invoiced}`}>
                      Invoiced ₱{returnItem.invoiced.toLocaleString()}
                    </span>
                  </div>

                  <button className="btn-view-details" type="button" aria-label={`View details for booking ${returnItem.bookingId}`}>
                    View Details
                  </button>
                </div>

                <div className="return-payments" aria-label="Payments and actions">
                  <div className="payment-row">
                    <div className="payment-text" aria-label={`Price ${returnItem.totalAmount.toLocaleString()} Philippine Peso`}>
                      <span>₱</span><span className="amount">{returnItem.totalAmount.toLocaleString()}</span>
                    </div>
                    <div>
                      <button className="btn-resolve-damage" type="button" aria-label={`Resolve damage for booking ${returnItem.bookingId}`}>
                        Resolve Damage
                      </button>
                    </div>
                  </div>
                  
                  {returnItem.status === 'paid' ? (
                    <button className="paid-btn" type="button" aria-label={`Payment status paid for booking ${returnItem.bookingId}`}>
                      Paid
                      <svg viewBox="0 0 25 25" stroke="currentColor" fill="none" strokeWidth="3" strokeLinejoin="round" strokeLinecap="round" aria-hidden="true" focusable="false" style={{ marginLeft: '4px', height: '18px', width: '18px', color: '#e1f0db' }}>
                        <polyline points="20 6 9 17 5 13"/>
                      </svg>
                    </button>
                  ) : returnItem.status === 'invoiced' ? (
                    <div className="payments-buttons">
                      <button className="btn-invoice" type="button" aria-label={`Invoice booking ${returnItem.bookingId}`}>
                        Invoice
                      </button>
                      <button className="btn-settle" type="button" ariaLabel={`Settle payment for booking ${returnItem.bookingId}`}>
                        Settle Payment
                      </button>
                    </div>
                  ) : (
                    <div className="pending-dropdown">
                      <button className="pending-btn" type="button">
                        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                          <circle cx="12" cy="12" r="10"/>
                          <polyline points="12 6 12 12 16 14"/>
                        </svg>
                        Pending
                      </button>
                    </div>
                  )}
                </div>
              </article>
            ))
          )}
        </section>

        {/* Info row */}
        <section className="info-row" aria-label="Returns benefits">
          <div>
            <svg width="48" height="48" fill="none" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" aria-hidden="true" focusable="false">
              <path d="M10 40h28M12 32h24M14 24h20" />
              <path d="M18 16h8" />
            </svg>
            <div>
              <strong>Affordable Rates</strong>
              <span>Great prices on all vehicle types</span>
            </div>
          </div>
          <div>
            <svg width="48" height="48" fill="none" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" aria-hidden="true" focusable="false">
              <path d="M32 24v-4a8 8 0 0 0-16 0v4" />
              <circle cx="32" cy="32" r="16" />
              <path d="M28 40h8M8 40h8" />
            </svg>
            <div>
              <strong>Safety &amp; Security</strong>
              <span>Well-maintained and safe rental cars</span>
            </div>
          </div>
          <div>
            <svg width="48" height="48" fill="none" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" aria-hidden="true" focusable="false">
              <path d="M42 36v4a10 10 0 0 1-20 0v-4" />
              <path d="M8 32v-8a12 12 0 0 1 24 0v8" />
              <line x1="10" y1="40" x2="38" y2="40" />
            </svg>
            <div>
              <strong>Easy Booking</strong>
              <span>Quick and Hassle free online reservations</span>
            </div>
          </div>
        </section>
      </div>
    </div>
  );
};

const styles = {
  container: {
    minHeight: '100vh',
    background: '#e7f2f1',
  },
  dashboardContent: {
    marginLeft: '250px',
    marginTop: '60px',
    padding: '30px',
    overflowY: 'auto',
    maxWidth: '1040px',
  },
  loading: {
    textAlign: 'center',
    padding: '40px',
    color: '#555',
  },
  emptyState: {
    textAlign: 'center',
    padding: '40px',
    color: '#555',
    background: 'white',
    borderRadius: '8px',
  },
};

const cssStyles = `
  /* Global Styles */
  body {
    font-family: Arial, sans-serif;
    background: #e7f2f1;
    margin: 20px auto;
    max-width: 1040px;
    color: #333;
    line-height: 1.4;
  }
  h2 {
    font-weight: 600;
    font-size: 22px;
    margin-bottom: 20px;
  }

  /* Filter bar */
  .filter-bar {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    align-items: center;
    margin-bottom: 25px;
  }
  .filter-bar button.status-filter {
    background-color: #6063f7;
    color: #fff;
    border: none;
    border-radius: 5px;
    font-weight: 600;
    padding: 6px 16px;
    cursor: pointer;
    user-select: none;
    transition: background-color 0.3s ease;
  }
  .filter-bar button.status-filter.inactive {
    background: white;
    color: #222;
    border: 1px solid #444;
  }
  .filter-bar button.status-filter:hover:not(.active) {
    background: #5254dd;
    color: white;
  }
  .filter-bar button.status-filter.active {
    background-color: #5054d2;
    color: white;
  }
  .filter-bar input[type="date"] {
    border-radius: 4px;
    border: 1px solid #888;
    padding: 7px 12px;
    font-size: 13px;
    cursor: pointer;
    min-width: 160px;
  }
  .filter-bar input[type="search"] {
    border: 1px solid #bbb;
    border-radius: 4px;
    font-size: 13px;
    padding: 7px 30px 7px 10px;
    width: 200px;
    font-family: Arial, sans-serif;
    color: #555;
    font-style: italic;
    background: url('data:image/svg+xml;utf8,<svg fill="none" stroke="%23777" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><circle cx="11" cy="11" r="7"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>') no-repeat right 8px center / 18px 18px;
  }
  .filter-bar button.filter-btn {
    background-color: #6063f7;
    color: white;
    border: none;
    border-radius: 6px;
    padding: 7px 18px;
    font-weight: 600;
    font-size: 13px;
    cursor: pointer;
    user-select: none;
    transition: background-color 0.3s ease;
    white-space: nowrap;
  }
  .filter-bar button.filter-btn:hover {
    background-color: #4b4fe4;
  }

  /* Returns container */
  section.returns-container {
    display: flex;
    flex-direction: column;
    gap: 14px;
  }

  article.return-card {
    background: white;
    border-radius: 9px;
    box-shadow: 2px 3px 10px 0 #ccc;
    border: 1px solid #b7b9f8;
    padding: 15px 20px;
    display: flex;
    gap: 20px;
    align-items: center;
  }

  /* Left image */
  article.return-card img {
    width: 130px;
    height: 90px;
    border-radius: 8px;
    user-select: none;
    object-fit: contain;
  }

  /* Info block */
  .return-info {
    flex-grow: 1;
    display: flex;
    flex-direction: column;
    gap: 5px;
  }

  .return-info strong.booking-id {
    font-weight: 700;
    font-size: 18px;
    user-select: text;
  }
  .return-info span.car-model {
    font-weight: 600;
    color: #222;
    font-size: 17px;
  }

  /* Status row and dates */
  .return-dates-status {
    display: flex;
    align-items: center;
    gap: 15px;
    font-size: 13px;
    color: #444;
    user-select: none;
  }
  .date-icon,
  .location-icon {
    display: flex;
    align-items: center;
    gap: 5px;
  }
  .date-icon svg,
  .location-icon svg {
    width: 18px;
    height: 18px;
    stroke: #444;
    stroke-width: 1.9;
    stroke-linejoin: round;
    stroke-linecap: round;
    fill: none;
    user-select: none;
  }
  .status-label-small {
    font-size: 13px;
    font-weight: 600;
    line-height: 1.1;
    color: #177c12;
    user-select: none;
    display: flex;
    align-items: center;
    gap: 5px;
  }
  .status-label-small.past {
    color: #3d8e2b;
  }
  .status-label-small.pending {
    color: #9e8000;
  }
  .status-label-small.invoiced {
    color: #0f158c;
  }

  /* 5 star rating */
  .stars {
    display: flex;
    margin: 4px 0 5px 0;
    gap: 2px;
  }
  .stars svg {
    stroke: #fdc30f;
    fill: #fdc30f;
    width: 18px;
    height: 18px;
  }
  .stars small {
    font-weight: 600;
    font-size: 13px;
    color: #333;
    margin-left: 10px;
    user-select: text;
  }

  /* Price and payment section */
  .return-payments {
    display: flex;
    flex-direction: column;
    gap: 7px;
    flex-shrink: 0;
    align-items: flex-end;
    min-width: 130px;
  }
  .payment-row {
    display: flex;
    flex-direction: column;
    gap: 6px;
    width: 130px;
  }
  .payment-row .payment-text {
    display: flex;
    justify-content: space-between;
    align-items: center;
    font-weight: 600;
    font-size: 13.6px;
    color: #444;
    user-select: none;
  }
  .payment-row .payment-text span.amount {
    font-weight: 700;
  }

  /* Buttons container for Resolve/Invoice/Settle */
  .payments-buttons {
    display: flex;
    gap: 8px;
    margin-top: 5px;
    flex-wrap: wrap;
  }
  .payments-buttons button {
    font-weight: 600;
    font-size: 12.8px;
    cursor: pointer;
    border-radius: 4px;
    padding: 5px 12px;
    white-space: nowrap;
    user-select: none;
    border: 1px solid transparent;
    transition: background-color 0.2s ease;
    min-width: 110px;
  }
  .btn-view-details {
    border: none;
    background-color: #4a74ce;
    color: white;
    border-radius: 4px;
    padding: 6px 16px;
    font-weight: 600;
    font-size: 13px;
    margin: 6px 0;
    cursor: pointer;
    user-select: none;
  }
  .btn-view-details:hover {
    background-color: #3658ad;
  }
  button.btn-resolve-damage {
    background: white;
    border: 1.5px solid #4a74ce;
    color: #4a74ce;
  }
  button.btn-resolve-damage:hover {
    background-color: #e8f0ff;
  }
  button.btn-invoice,
  button.btn-settle {
    background: white;
    border: 1px solid #288d3b;
    color: #288d3b;
  }
  button.btn-invoice:hover,
  button.btn-settle:hover {
    background-color: #cdf2bd;
  }
  button.paid-btn {
    cursor: default;
    font-weight: 600;
    font-size: 14px;
    border-radius: 4px;
    border: none;
    color: #fff;
    background-color: #287622;
    user-select: none;
    padding: 6px 13px;
    min-width: 110px;
  }
  button.paid-btn svg {
    vertical-align: middle;
    margin-left: 7px;
    font-size: 18px;
  }

  /* Pending dropdown styling */
  .pending-dropdown {
    position: relative;
    user-select: none;
  }
  .pending-btn {
    background-color: #ffee9d;
    border: 1px solid #d3bf73;
    font-weight: 600;
    font-size: 13px;
    color: #856b00;
    border-radius: 4px;
    padding: 6px 14px;
    cursor: default;
    display: flex;
    align-items: center;
    gap: 6px;
    min-width: 110px;
    justify-content: center;
  }
  .pending-btn svg {
    font-size: 18px;
  }

  /* Info row bottom */
  section.info-row {
    margin-top: 45px;
    display: flex;
    justify-content: space-between;
    background: white;
    border-radius: 8px;
    box-shadow: 0 2px 5px #ccc;
    padding: 18px 30px;
    max-width: 100%;
  }
  section.info-row > div {
    display: flex;
    align-items: center;
    gap: 20px;
    max-width: 33%;
  }
  section.info-row svg {
    width: 48px;
    height: 48px;
    stroke: #222;
  }
  section.info-row div > div {
    display: flex;
    flex-direction: column;
  }
  section.info-row div > div strong {
    font-size: 20px;
    font-weight: 700;
    line-height: 1.1;
  }
  section.info-row div > div span {
    font-size: 0.88rem;
    color: #222;
    font-weight: 600;
  }

  /* Responsive */
  @media (max-width: 875px) {
    body {
      margin: 10px 12px;
    }
    .filter-bar {
      gap: 8px;
    }
    .returns-container {
      gap: 12px;
    }
    article.return-card {
      display: block;
      padding: 14px 14px 20px 14px;
      box-shadow: 2px 2px 12px #999;
    }
    article.return-card img {
      width: 100%;
      height: 140px;
      object-fit: contain;
      margin-bottom: 8px;
      border-radius: 6px;
    }
    .return-info {
      gap: 3px;
    }
    .return-dates-status {
      gap: 8px;
    }
    .return-payments {
      flex-direction: row;
      justify-content: flex-start;
      margin-top: 12px;
      gap: 12px;
      width: 100%;
      max-width: 100%;
      align-items: center;
    }
    .payment-row {
      width: auto;
      min-width: auto;
    }
    .payments-buttons {
      flex-wrap: wrap;
      gap: 8px;
    }
  }
`;

export default MyReturns;
